  1→"use client";
  2→
  3→import { useCallback, useRef, useEffect, useState } from "react";
  4→import { useFlowStore } from "@/store/useFlowStore";
  5→import { useLocale } from "@/lib/i18n/useLocale";
  6→import type { EdgeType, MarkerStyle } from "@/types/flow";
  7→import type { TranslationKey } from "@/lib/i18n/locales";
  8→import { computeColor } from "@/lib/color";
  9→
 10→interface MenuPosition {
 11→  x: number;
 12→  y: number;
 13→}
 14→
 15→interface ContextMenuState {
 16→  position: MenuPosition | null;
 17→  nodeIds: string[];
 18→  edgeIds: string[];
 19→}
 20→
 21→const COLORS: { key: TranslationKey; value: string }[] = [
 22→  { key: "colorDefault", value: "" },
 23→  { key: "colorRed", value: "#ef4444" },
 24→  { key: "colorOrange", value: "#f97316" },
 25→  { key: "colorYellow", value: "#eab308" },
 26→  { key: "colorGreen", value: "#22c55e" },
 27→  { key: "colorBlue", value: "#3b82f6" },
 28→  { key: "colorPurple", value: "#a855f7" },
 29→  { key: "colorPink", value: "#ec4899" },
 30→  { key: "colorWhite", value: "#ffffff" },
 31→  { key: "colorBlack", value: "#000000" },
 32→];
 33→
 34→function IconBezier() {
 35→  return (
 36→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 37→      <path d="M 2 12 C 8 12, 12 2, 18 2" />
 38→    </svg>
 39→  );
 40→}
 41→function IconStraight() {
 42→  return (
 43→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 44→      <line x1="2" y1="12" x2="18" y2="2" />
 45→    </svg>
 46→  );
 47→}
 48→function IconStep() {
 49→  return (
 50→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 51→      <polyline points="2,12 2,7 18,7 18,2" />
 52→    </svg>
 53→  );
 54→}
 55→function IconArrowClosed() {
 56→  return (
 57→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 58→      <line x1="2" y1="7" x2="14" y2="7" />
 59→      <polygon points="14,3 20,7 14,11" fill="currentColor" stroke="none" />
 60→    </svg>
 61→  );
 62→}
 63→function IconArrowOpen() {
 64→  return (
 65→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 66→      <line x1="2" y1="7" x2="18" y2="7" />
 67→      <polyline points="14,3 20,7 14,11" />
 68→    </svg>
 69→  );
 70→}
 71→function IconNoArrow() {
 72→  return (
 73→    <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="1.5">
 74→      <line x1="2" y1="7" x2="18" y2="7" />
 75→    </svg>
 76→  );
 77→}
 78→
 79→const EDGE_TYPES: { key: TranslationKey; value: EdgeType; icon: React.ReactNode }[] = [
 80→  { key: "bezier", value: "bezier", icon: <IconBezier /> },
 81→  { key: "straight", value: "straight", icon: <IconStraight /> },
 82→  { key: "step", value: "step", icon: <IconStep /> },
 83→];
 84→
 85→const MARKER_STYLES: { key: TranslationKey; value: MarkerStyle; icon: React.ReactNode }[] = [
 86→  { key: "arrow", value: "arrowclosed", icon: <IconArrowClosed /> },
 87→  { key: "openArrow", value: "arrow", icon: <IconArrowOpen /> },
 88→  { key: "none", value: "none", icon: <IconNoArrow /> },
 89→];
 90→
 91→export function useContextMenu() {
 92→  const [menu, setMenu] = useState<ContextMenuState>({
 93→    position: null,
 94→    nodeIds: [],
 95→    edgeIds: [],
 96→  });
 97→
 98→  const open = useCallback(
 99→    (e: React.MouseEvent, nodeIds: string[], edgeIds: string[]) => {
100→      e.preventDefault();
101→      setMenu({ position: { x: e.clientX, y: e.clientY }, nodeIds, edgeIds });
102→    },
103→    []
104→  );
105→
106→  const close = useCallback(() => {
107→    setMenu({ position: null, nodeIds: [], edgeIds: [] });
108→  }, []);
109→
110→  return { menu, open, close };
111→}
112→
113→interface ContextMenuProps {
114→  position: MenuPosition;
115→  nodeIds: string[];
116→  edgeIds: string[];
117→  onClose: () => void;
118→}
119→
120→function SubMenu({ label, children }: { label: string; children: React.ReactNode }) {
121→  const [open, setOpen] = useState(false);
122→  const subRef = useRef<HTMLDivElement>(null);
123→  const [pos, setPos] = useState<{ left?: string; right?: string; top: string }>({ top: "0" });
124→
125→  useEffect(() => {
126→    if (!open || !subRef.current) return;
127→    const rect = subRef.current.getBoundingClientRect();
128→    const vw = window.innerWidth;
129→    const vh = window.innerHeight;
130→    const newPos: { left?: string; right?: string; top: string } = { top: "0" };
131→    // Flip to left if overflowing right
132→    if (rect.right > vw) {
133→      newPos.right = "100%";
134→    } else {
135→      newPos.left = "100%";
136→    }
137→    // Shift up if overflowing bottom
138→    if (rect.bottom > vh) {
139→      newPos.top = `${vh - rect.bottom}px`;
140→    }
141→    setPos(newPos);
142→  }, [open]);
143→
144→  return (
145→    <div
146→      className="relative"
147→      onMouseEnter={() => setOpen(true)}
148→      onMouseLeave={() => { setOpen(false); setPos({ top: "0" }); }}
149→    >
150→      <div className="ctx-item flex items-center justify-between">
151→        {label}
152→        <span className="ml-4 text-[10px]">▶</span>
153→      </div>
154→      {open && (
155→        <div
156→          ref={subRef}
157→          className="absolute ctx-menu"
158→          style={{ left: pos.left, right: pos.right, top: pos.top, marginLeft: pos.left ? 2 : undefined, marginRight: pos.right ? 2 : undefined }}
159→        >
160→          {children}
161→        </div>
162→      )}
163→    </div>
164→  );
165→}
166→
167→function ColorSubMenu({
168→  label,
169→  colors,
170→  defaultSwatchClass,
171→  storedOpacity,
172→  storedLightness,
173→  onSelect,
174→  onOpacityChange,
175→  onLightnessChange,
176→  t,
177→}: {
178→  label: string;
179→  colors: typeof COLORS;
180→  defaultSwatchClass?: string;
181→  storedOpacity?: number;
182→  storedLightness?: number;
183→  onSelect: (color: string | null, opacity: number, lightness: number) => void;
184→  onOpacityChange: (value: number) => void;
185→  onLightnessChange: (value: number) => void;
186→  t: (key: TranslationKey) => string;
187→}) {
188→  const [opacity, setOpacity] = useState(storedOpacity ?? 10);
189→  const [lightness, setLightness] = useState(storedLightness ?? 5);
190→
191→  return (
192→    <SubMenu label={label}>
193→      {colors.map((c) => {
194→        const adjusted = c.value ? computeColor(c.value, opacity, lightness) : undefined;
195→        return (
196→          <div
197→            key={c.key}
198→            className="ctx-item flex items-center gap-2"
199→            onClick={() => {
200→              if (c.value) {
201→                onSelect(c.value, opacity, lightness);
202→              } else {
203→                setOpacity(10);
204→                setLightness(5);
205→                onSelect(null, 10, 5);
206→              }
207→            }}
208→          >
209→            {adjusted ? (
210→              <span className="w-3 h-3 rounded-sm border border-border inline-block" style={{ background: adjusted }} />
211→            ) : (
212→              <span className={`w-3 h-3 rounded-sm border border-border inline-block ${defaultSwatchClass ?? "bg-background"}`} />
213→            )}
214→            {t(c.key)}
215→          </div>
216→        );
217→      })}
218→      <div className="ctx-separator" />
219→      <div className="px-2 py-1.5" onPointerDown={(e) => e.stopPropagation()}>
220→        <div className="flex items-center justify-between mb-1">
221→          <span className="text-[11px] text-muted-foreground">{t("transparency")}</span>
222→          <span className="text-[11px] text-muted-foreground tabular-nums">{opacity}</span>
223→        </div>
224→        <input
225→          type="range"
226→          min={0}
227→          max={10}
228→          step={1}
229→          value={opacity}
230→          onChange={(e) => {
231→            const v = Number(e.target.value);
232→            setOpacity(v);
233→            onOpacityChange(v);
234→          }}
235→          className="w-full h-1.5 accent-primary cursor-pointer"
236→        />
237→      </div>
238→      <div className="px-2 py-1.5" onPointerDown={(e) => e.stopPropagation()}>
239→        <div className="flex items-center justify-between mb-1">
240→          <span className="text-[11px] text-muted-foreground">{t("brightness")}</span>
241→          <span className="text-[11px] text-muted-foreground tabular-nums">{lightness}</span>
242→        </div>
243→        <input
244→          type="range"
245→          min={0}
246→          max={10}
247→          step={1}
248→          value={lightness}
249→          onChange={(e) => {
250→            const v = Number(e.target.value);
251→            setLightness(v);
252→            onLightnessChange(v);
253→          }}
254→          className="w-full h-1.5 accent-primary cursor-pointer"
255→        />
256→      </div>
257→    </SubMenu>
258→  );
259→}
260→
261→export function ContextMenu({ position, nodeIds, edgeIds, onClose }: ContextMenuProps) {
262→  const ref = useRef<HTMLDivElement>(null);
263→  const nodes = useFlowStore((s) => s.nodes);
264→  const removeNodes = useFlowStore((s) => s.removeNodes);
265→  const removeEdges = useFlowStore((s) => s.removeEdges);
266→  const duplicateNodes = useFlowStore((s) => s.duplicateNodes);
267→  const updateNodeColors = useFlowStore((s) => s.updateNodeColors);
268→  const updateNodeBorder = useFlowStore((s) => s.updateNodeBorder);
269→  const updateEdgeType = useFlowStore((s) => s.updateEdgeType);
270→  const updateEdgeMarkers = useFlowStore((s) => s.updateEdgeMarkers);
271→  const updateEdgeStyle = useFlowStore((s) => s.updateEdgeStyle);
272→  const updateNodeColorAdjust = useFlowStore((s) => s.updateNodeColorAdjust);
273→  const updateNodeTextStyle = useFlowStore((s) => s.updateNodeTextStyle);
274→  const updateEdgeColorAdjust = useFlowStore((s) => s.updateEdgeColorAdjust);
275→  const alignNodes = useFlowStore((s) => s.alignNodes);
276→  const distributeNodes = useFlowStore((s) => s.distributeNodes);
277→  const reorderNodes = useFlowStore((s) => s.reorderNodes);
278→  const edges = useFlowStore((s) => s.edges);
279→  const { t } = useLocale();
280→
281→  const enterComponentEditMode = useFlowStore((s) => s.enterComponentEditMode);
282→
283→  // First selected node/edge data for initial slider values
284→  const firstNode = nodeIds.length > 0 ? nodes.find((n) => n.id === nodeIds[0]) : undefined;
285→  const firstNodeData = firstNode?.data;
286→  const firstEdge = edgeIds.length > 0 ? edges.find((e) => e.id === edgeIds[0]) : undefined;
287→  const firstEdgeData = firstEdge?.data;
288→
289→  useEffect(() => {
290→    const handlePointerDown = (e: PointerEvent) => {
291→      if (ref.current && !ref.current.contains(e.target as Node)) onClose();
292→    };
293→    const handleKey = (e: KeyboardEvent) => {
294→      if (e.key === "Escape") onClose();
295→    };
296→    document.addEventListener("pointerdown", handlePointerDown, true);
297→    document.addEventListener("contextmenu", handlePointerDown);
298→    document.addEventListener("keydown", handleKey);
299→    window.addEventListener("scroll", onClose, true);
300→    return () => {
301→      document.removeEventListener("pointerdown", handlePointerDown, true);
302→      document.removeEventListener("contextmenu", handlePointerDown);
303→      document.removeEventListener("keydown", handleKey);
304→      window.removeEventListener("scroll", onClose, true);
305→    };
306→  }, [onClose]);
307→
308→  // Adjust main menu position to stay within viewport
309→  const [adjustedPos, setAdjustedPos] = useState(position);
310→  useEffect(() => {
311→    if (!ref.current) return;
312→    const rect = ref.current.getBoundingClientRect();
313→    const vw = window.innerWidth;
314→    const vh = window.innerHeight;
315→    let x = position.x;
316→    let y = position.y;
317→    if (rect.right > vw) x = Math.max(0, vw - rect.width);
318→    if (rect.bottom > vh) y = Math.max(0, vh - rect.height);
319→    if (x !== adjustedPos.x || y !== adjustedPos.y) setAdjustedPos({ x, y });
320→  }, [position]); // eslint-disable-line react-hooks/exhaustive-deps
321→
322→  const hasNodes = nodeIds.length > 0;
323→  const hasEdges = edgeIds.length > 0;
324→  const multipleNodes = nodeIds.length >= 2;
325→
326→  return (
327→    <div
328→      ref={ref}
329→      className="ctx-menu"
330→      style={{ position: "fixed", left: adjustedPos.x, top: adjustedPos.y, zIndex: 1000 }}
331→    >
332→      {hasNodes && (
333→        <>
334→          <div
335→            className="ctx-item"
336→            onClick={() => { duplicateNodes(nodeIds); onClose(); }}
337→          >
338→            {t("duplicate")}
339→          </div>
340→          <ColorSubMenu
341→            label={t("fillColor")}
342→            colors={COLORS}
343→            storedOpacity={firstNodeData?.fillOpacity as number | undefined}
344→            storedLightness={firstNodeData?.fillLightness as number | undefined}
345→            onSelect={(color, op, lt) => {
346→              nodeIds.forEach((id) => {
347→                updateNodeColors(id, color, undefined);
348→                updateNodeColorAdjust(id, "fill", op, lt);
349→              });
350→              onClose();
351→            }}
352→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "fill", v, undefined))}
353→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "fill", undefined, v))}
354→            t={t}
355→          />
356→          <ColorSubMenu
357→            label={t("borderColor")}
358→            colors={COLORS}
359→            defaultSwatchClass="bg-muted-foreground"
360→            storedOpacity={firstNodeData?.borderOpacity as number | undefined}
361→            storedLightness={firstNodeData?.borderLightness as number | undefined}
362→            onSelect={(color, op, lt) => {
363→              nodeIds.forEach((id) => {
364→                updateNodeColors(id, undefined, color);
365→                updateNodeColorAdjust(id, "border", op, lt);
366→              });
367→              onClose();
368→            }}
369→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "border", v, undefined))}
370→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "border", undefined, v))}
371→            t={t}
372→          />
373→          <ColorSubMenu
374→            label={t("textColor")}
375→            colors={COLORS}
376→            defaultSwatchClass="bg-foreground"
377→            storedOpacity={firstNodeData?.textOpacity as number | undefined}
378→            storedLightness={firstNodeData?.textLightness as number | undefined}
379→            onSelect={(color, op, lt) => {
380→              nodeIds.forEach((id) => {
381→                updateNodeTextStyle(id, { textColor: color ?? undefined });
382→                updateNodeColorAdjust(id, "text", op, lt);
383→              });
384→              onClose();
385→            }}
386→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "text", v, undefined))}
387→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "text", undefined, v))}
388→            t={t}
389→          />
390→          <SubMenu label={t("borderWidth")}>
391→            {([
392→              { key: "thin" as const, value: 1 },
393→              { key: "normal" as const, value: 2 },
394→              { key: "thick" as const, value: 4 },
395→            ]).map((w) => (
396→              <div
397→                key={w.value}
398→                className="ctx-item flex items-center gap-2"
399→                onClick={() => {
400→                  nodeIds.forEach((id) => updateNodeBorder(id, w.value, undefined));
401→                  onClose();
402→                }}
403→              >
404→                <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor">
405→                  <rect x="2" y={7 - w.value / 2} width="16" height={w.value} fill="currentColor" />
406→                </svg>
407→                {t(w.key)}
408→              </div>
409→            ))}
410→          </SubMenu>
411→          <SubMenu label={t("borderLineStyle")}>
412→            {([
413→              { key: "solid" as const, value: "solid" as const },
414→              { key: "dashed" as const, value: "dashed" as const },
415→              { key: "dotted" as const, value: "dotted" as const },
416→            ]).map((s) => (
417→              <div
418→                key={s.value}
419→                className="ctx-item flex items-center gap-2"
420→                onClick={() => {
421→                  nodeIds.forEach((id) => updateNodeBorder(id, undefined, s.value));
422→                  onClose();
423→                }}
424→              >
425→                <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="2">
426→                  <line
427→                    x1="2" y1="7" x2="18" y2="7"
428→                    strokeDasharray={s.value === "dashed" ? "4 2" : s.value === "dotted" ? "1.5 1.5" : undefined}
429→                  />
430→                </svg>
431→                {t(s.key)}
432→              </div>
433→            ))}
434→          </SubMenu>
435→          <SubMenu label={t("order")}>
436→            <div className="ctx-item flex items-center gap-2" onClick={() => { reorderNodes(nodeIds, "front"); onClose(); }}>
437→              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
438→                <rect x="1" y="1" width="8" height="8" fill="var(--foreground)" fillOpacity="0.25" />
439→                <rect x="7" y="7" width="8" height="8" fill="var(--foreground)" fillOpacity="0.6" />
440→              </svg>
441→              {t("bringToFront")}
442→            </div>
443→            <div className="ctx-item flex items-center gap-2" onClick={() => { reorderNodes(nodeIds, "forward"); onClose(); }}>
444→              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
445→                <rect x="1" y="1" width="8" height="8" fill="var(--foreground)" fillOpacity="0.25" />
446→                <rect x="7" y="7" width="8" height="8" fill="var(--foreground)" fillOpacity="0.45" />
447→              </svg>
448→              {t("bringForward")}
449→            </div>
450→            <div className="ctx-separator" />
451→            <div className="ctx-item flex items-center gap-2" onClick={() => { reorderNodes(nodeIds, "backward"); onClose(); }}>
452→              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
453→                <rect x="7" y="7" width="8" height="8" fill="var(--foreground)" fillOpacity="0.45" />
454→                <rect x="1" y="1" width="8" height="8" fill="var(--foreground)" fillOpacity="0.25" />
455→              </svg>
456→              {t("sendBackward")}
457→            </div>
458→            <div className="ctx-item flex items-center gap-2" onClick={() => { reorderNodes(nodeIds, "back"); onClose(); }}>
459→              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
460→                <rect x="7" y="7" width="8" height="8" fill="var(--foreground)" fillOpacity="0.6" />
461→                <rect x="1" y="1" width="8" height="8" fill="var(--foreground)" fillOpacity="0.15" />
462→              </svg>
463→              {t("sendToBack")}
464→            </div>
465→          </SubMenu>
466→          {multipleNodes && (
467→            <>
468→              <div className="ctx-separator" />
469→              <SubMenu label={t("align")}>
470→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "left"); onClose(); }}>{t("left")}</div>
471→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "center"); onClose(); }}>{t("center")}</div>
472→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "right"); onClose(); }}>{t("right")}</div>
473→                <div className="ctx-separator" />
474→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "top"); onClose(); }}>{t("top")}</div>
475→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "middle"); onClose(); }}>{t("middle")}</div>
476→                <div className="ctx-item" onClick={() => { alignNodes(nodeIds, "bottom"); onClose(); }}>{t("bottom")}</div>
477→              </SubMenu>
478→              {nodeIds.length >= 3 && (
479→                <SubMenu label={t("distribute")}>
480→                  <div className="ctx-item" onClick={() => { distributeNodes(nodeIds, "horizontal"); onClose(); }}>{t("horizontal")}</div>
481→                  <div className="ctx-item" onClick={() => { distributeNodes(nodeIds, "vertical"); onClose(); }}>{t("vertical")}</div>
482→                </SubMenu>
483→              )}
484→            </>
485→          )}
486→          {/* Component instance: edit definition */}
487→          {nodeIds.length === 1 && (() => {
488→            const nd = nodes.find((n) => n.id === nodeIds[0]);
489→            return nd?.type === "componentInstance" && nd.data.componentDefinitionId;
490→          })() && (
491→            <>
492→              <div className="ctx-separator" />
493→              <div
494→                className="ctx-item"
495→                onClick={() => {
496→                  const nd = nodes.find((n) => n.id === nodeIds[0]);
497→                  if (nd?.data.componentDefinitionId) {
498→                    enterComponentEditMode(nd.data.componentDefinitionId as string);
499→                  }
500→                  onClose();
501→                }}
502→              >
503→                {t("editDefinition")}
504→              </div>
505→            </>
506→          )}
507→          <div className="ctx-separator" />
508→          <div
509→            className="ctx-item text-destructive"
510→            onClick={() => { removeNodes(nodeIds); onClose(); }}
511→          >
512→            {nodeIds.length > 1 ? t("deleteNodes") : t("deleteNode")}
513→          </div>
514→        </>
515→      )}
516→      {hasEdges && (
517→        <>
518→          {hasNodes && <div className="ctx-separator" />}
519→          <SubMenu label={t("lineType")}>
520→            {EDGE_TYPES.map((et) => (
521→              <div
522→                key={et.value}
523→                className="ctx-item flex items-center gap-2"
524→                onClick={() => {
525→                  edgeIds.forEach((id) => updateEdgeType(id, et.value));
526→                  onClose();
527→                }}
528→              >
529→                {et.icon}
530→                {t(et.key)}
531→              </div>
532→            ))}
533→          </SubMenu>
534→          <SubMenu label={t("arrowEnd")}>
535→            {MARKER_STYLES.map((m) => (
536→              <div
537→                key={m.value}
538→                className="ctx-item flex items-center gap-2"
539→                onClick={() => {
540→                  edgeIds.forEach((id) => updateEdgeMarkers(id, undefined, m.value));
541→                  onClose();
542→                }}
543→              >
544→                {m.icon}
545→                {t(m.key)}
