219→/** Determine which segment index a click position is closest to */
220→function findClosestSegment(allPts: Waypoint[], clickPos: Waypoint): number {
221→  let bestIdx = 0;
222→  let bestDist = Infinity;
223→  for (let i = 0; i < allPts.length - 1; i++) {
224→    // Distance from point to line segment
225→    const a = allPts[i];
226→    const b = allPts[i + 1];
227→    const dx = b.x - a.x;
228→    const dy = b.y - a.y;
229→    const len2 = dx * dx + dy * dy;
230→    let t = len2 === 0 ? 0 : Math.max(0, Math.min(1, ((clickPos.x - a.x) * dx + (clickPos.y - a.y) * dy) / len2));
231→    const px = a.x + t * dx;
232→    const py = a.y + t * dy;
233→    const dist = Math.hypot(clickPos.x - px, clickPos.y - py);
234→    if (dist < bestDist) {
235→      bestDist = dist;
236→      bestIdx = i;
237→    }
238→  }
239→  return bestIdx;
240→}
