120→function SubMenu({ label, children }: { label: string; children: React.ReactNode }) {
121→  const [open, setOpen] = useState(false);
122→  const subRef = useRef<HTMLDivElement>(null);
123→  const [pos, setPos] = useState<{ left?: string; right?: string; top: string }>({ top: "0" });
124→
125→  useEffect(() => {
126→    if (!open || !subRef.current) return;
127→    const rect = subRef.current.getBoundingClientRect();
128→    const vw = window.innerWidth;
129→    const vh = window.innerHeight;
130→    const newPos: { left?: string; right?: string; top: string } = { top: "0" };
131→    // Flip to left if overflowing right
132→    if (rect.right > vw) {
133→      newPos.right = "100%";
134→    } else {
135→      newPos.left = "100%";
136→    }
137→    // Shift up if overflowing bottom
138→    if (rect.bottom > vh) {
139→      newPos.top = `${vh - rect.bottom}px`;
140→    }
141→    setPos(newPos);
142→  }, [open]);
143→
144→  return (
145→    <div
146→      className="relative"
147→      onMouseEnter={() => setOpen(true)}
148→      onMouseLeave={() => { setOpen(false); setPos({ top: "0" }); }}
149→    >
150→      <div className="ctx-item flex items-center justify-between">
151→        {label}
152→        <span className="ml-4 text-[10px]">▶</span>
153→      </div>
154→      {open && (
155→        <div
156→          ref={subRef}
157→          className="absolute ctx-menu"
158→          style={{ left: pos.left, right: pos.right, top: pos.top, marginLeft: pos.left ? 2 : undefined, marginRight: pos.right ? 2 : undefined }}
159→        >
160→          {children}
161→        </div>
162→      )}
163→    </div>
164→  );
165→}
