480→                  <div className="ctx-item" onClick={() => { distributeNodes(nodeIds, "horizontal"); onClose(); }}>{t("horizontal")}</div>
481→                  <div className="ctx-item" onClick={() => { distributeNodes(nodeIds, "vertical"); onClose(); }}>{t("vertical")}</div>
482→                </SubMenu>
483→              )}
484→            </>
485→          )}
486→          {/* Component instance: edit definition */}
487→          {nodeIds.length === 1 && (() => {
488→            const nd = nodes.find((n) => n.id === nodeIds[0]);
489→            return nd?.type === "componentInstance" && nd.data.componentDefinitionId;
490→          })() && (
491→            <>
492→              <div className="ctx-separator" />
493→              <div
494→                className="ctx-item"
495→                onClick={() => {
