.react-flow .react-flow__handle {
  overflow: visible !important;
}

.react-flow .react-flow__handle::after {
  content: none;
}

/* Hide React Flow's default edge update anchors (reconnection is handled by ring handles) */
.react-flow__edgeupdater {
  display: none !important;
}

/* Hide the original edge while reconnecting from ring handle */
.react-flow__edge.reconnecting {
  visibility: hidden;
}

/* Ghost node/edge (predictive input preview — always visible, very faint) */
.react-flow__node[data-id^="__ghost__"] {
  opacity: 0.15;
  cursor: pointer;
  transition: opacity 0.15s ease;
}
.react-flow__node[data-id^="__ghost__"]:hover {
  opacity: 0.4;
}
.react-flow__edge[data-id^="__ghost_edge__"] {
  opacity: 0.15;
  pointer-events: none;

