319→  const processEdgesChanges = useCallback(
320→    <E extends Edge = Edge>(changes: EdgeChange<E>[]): EdgeChange<E>[] => {
321→      let hasSelect = false;
322→      for (const c of changes) { if (c.type === "select") { hasSelect = true; break; } }
323→      if (!hasSelect) return changes;
324→
325→      const rest: EdgeChange<E>[] = [];
326→      for (const c of changes) { if (c.type !== "select") rest.push(c); }
327→
328→      // During drag, edge selection is fully managed by processNodesChanges.
329→      if (isDragging.current) return rest;
330→
331→      // When Ctrl is held (non-drag): block only resetSelectedElements (userSelectionRect set).
332→      // Allow Ctrl+click edge changes through.
333→      if (isMultiSelectKeyHeld.current) {
334→        const { userSelectionRect } = rfStore.getState();
335→        if (userSelectionRect) {
336→          // BLOCK — resetSelectedElements before drag start.
337→          // Do NOT repair here (same reason as processNodesChanges BLOCK branch).
338→          return rest;
339→        }
340→      }
341→
342→      // Non-drag, non-ctrl or Ctrl+click: apply ReactFlow's edge selection changes.
343→      const o = optsRef.current;
344→      const next = new Set(o.getSelectedIds());
345→      for (const c of changes) {
346→        if (c.type === "select") {
347→          if (c.selected) next.add(c.id);
348→          else next.delete(c.id);
349→        }
350→      }
351→      applyIfChanged(next, o.getSelectedIds, o.setSelectedIds);
352→      return rest;
353→    },
354→    [],
355→  );
