185→function ColorSubMenu({
186→  label,
187→  colors,
188→  defaultSwatchClass,
189→  storedOpacity,
190→  storedLightness,
191→  onSelect,
192→  onOpacityChange,
193→  onLightnessChange,
194→  t,
195→}: {
196→  label: string;
197→  colors: typeof COLORS;
198→  defaultSwatchClass?: string;
199→  storedOpacity?: number;
