279→export function ContextMenu({ position, nodeIds, edgeIds, onClose }: ContextMenuProps) {
280→  const ref = useRef<HTMLDivElement>(null);
281→  const nodes = useFlowStore((s) => s.nodes);
282→  const removeNodes = useFlowStore((s) => s.removeNodes);
283→  const removeEdges = useFlowStore((s) => s.removeEdges);
284→  const updateNodeShape = useFlowStore((s) => s.updateNodeShape);
285→  const updateNodeColors = useFlowStore((s) => s.updateNodeColors);
286→  const updateNodeBorder = useFlowStore((s) => s.updateNodeBorder);
287→  const updateEdgeType = useFlowStore((s) => s.updateEdgeType);
288→  const updateEdgeMarkers = useFlowStore((s) => s.updateEdgeMarkers);
289→  const updateEdgeStyle = useFlowStore((s) => s.updateEdgeStyle);
290→  const updateNodeColorAdjust = useFlowStore((s) => s.updateNodeColorAdjust);
291→  const updateNodeTextStyle = useFlowStore((s) => s.updateNodeTextStyle);
292→  const updateEdgeColorAdjust = useFlowStore((s) => s.updateEdgeColorAdjust);
293→  const alignNodes = useFlowStore((s) => s.alignNodes);
294→  const distributeNodes = useFlowStore((s) => s.distributeNodes);
295→  const reorderNodes = useFlowStore((s) => s.reorderNodes);
296→  const edges = useFlowStore((s) => s.edges);
297→  const { t } = useLocale();
298→
299→  const enterComponentEditMode = useFlowStore((s) => s.enterComponentEditMode);
300→
301→  // First selected node/edge data for initial slider values
302→  const firstNode = nodeIds.length > 0 ? nodes.find((n) => n.id === nodeIds[0]) : undefined;
303→  const firstNodeData = firstNode?.data;
304→  const firstEdge = edgeIds.length > 0 ? edges.find((e) => e.id === edgeIds[0]) : undefined;
305→  const firstEdgeData = firstEdge?.data;
306→
307→  useEffect(() => {
308→    const handlePointerDown = (e: PointerEvent) => {
309→      if (ref.current && !ref.current.contains(e.target as Node)) onClose();
310→    };
311→    const handleKey = (e: KeyboardEvent) => {
312→      if (e.key === "Escape") onClose();
313→    };
314→    document.addEventListener("pointerdown", handlePointerDown, true);
315→    document.addEventListener("contextmenu", handlePointerDown);
316→    document.addEventListener("keydown", handleKey);
317→    window.addEventListener("scroll", onClose, true);
318→    return () => {
319→      document.removeEventListener("pointerdown", handlePointerDown, true);
320→      document.removeEventListener("contextmenu", handlePointerDown);
321→      document.removeEventListener("keydown", handleKey);
322→      window.removeEventListener("scroll", onClose, true);
323→    };
324→  }, [onClose]);
325→
326→  // Adjust main menu position to stay within viewport
327→  const [adjustedPos, setAdjustedPos] = useState(position);
328→  useEffect(() => {
329→    if (!ref.current) return;
330→    const rect = ref.current.getBoundingClientRect();
331→    const vw = window.innerWidth;
332→    const vh = window.innerHeight;
333→    let x = position.x;
334→    let y = position.y;
335→    if (rect.right > vw) x = Math.max(0, vw - rect.width);
336→    if (rect.bottom > vh) y = Math.max(0, vh - rect.height);
337→    if (x !== adjustedPos.x || y !== adjustedPos.y) setAdjustedPos({ x, y });
338→  }, [position]); // eslint-disable-line react-hooks/exhaustive-deps
339→
340→  const hasNodes = nodeIds.length > 0;
341→  const hasEdges = edgeIds.length > 0;
342→  const multipleNodes = nodeIds.length >= 2;
343→
344→  return (
345→    <div
346→      ref={ref}
347→      className="ctx-menu"
348→      style={{ position: "fixed", left: adjustedPos.x, top: adjustedPos.y, zIndex: 1000 }}
349→    >
350→      {hasNodes && (
351→        <>
352→          <SubMenu label={t("changeShape")}>
353→            {SHAPE_ITEMS.map((s) => (
354→              <div
355→                key={s.value}
356→                className="ctx-item"
357→                onClick={() => {
358→                  nodeIds.forEach((id) => updateNodeShape(id, s.value));
359→                  onClose();
360→                }}
361→              >
362→                {t(s.key)}
363→              </div>
364→            ))}
365→          </SubMenu>
366→          <ColorSubMenu
367→            label={t("fillColor")}
368→            colors={COLORS}
369→            storedOpacity={firstNodeData?.fillOpacity as number | undefined}
370→            storedLightness={firstNodeData?.fillLightness as number | undefined}
371→            onSelect={(color, op, lt) => {
372→              nodeIds.forEach((id) => {
373→                updateNodeColors(id, color, undefined);
374→                updateNodeColorAdjust(id, "fill", op, lt);
375→              });
376→              onClose();
377→            }}
378→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "fill", v, undefined))}
379→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "fill", undefined, v))}
380→            t={t}
381→          />
382→          <ColorSubMenu
383→            label={t("borderColor")}
384→            colors={COLORS}
385→            defaultSwatchClass="bg-muted-foreground"
386→            storedOpacity={firstNodeData?.borderOpacity as number | undefined}
387→            storedLightness={firstNodeData?.borderLightness as number | undefined}
388→            onSelect={(color, op, lt) => {
389→              nodeIds.forEach((id) => {
390→                updateNodeColors(id, undefined, color);
391→                updateNodeColorAdjust(id, "border", op, lt);
392→              });
393→              onClose();
394→            }}
395→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "border", v, undefined))}
396→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "border", undefined, v))}
397→            t={t}
398→          />
399→          <ColorSubMenu
400→            label={t("textColor")}
401→            colors={COLORS}
402→            defaultSwatchClass="bg-foreground"
403→            storedOpacity={firstNodeData?.textOpacity as number | undefined}
404→            storedLightness={firstNodeData?.textLightness as number | undefined}
405→            onSelect={(color, op, lt) => {
406→              nodeIds.forEach((id) => {
407→                updateNodeTextStyle(id, { textColor: color ?? "" });
408→                updateNodeColorAdjust(id, "text", op, lt);
409→              });
410→              onClose();
411→            }}
412→            onOpacityChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "text", v, undefined))}
413→            onLightnessChange={(v) => nodeIds.forEach((id) => updateNodeColorAdjust(id, "text", undefined, v))}
414→            t={t}
415→          />
416→          <SubMenu label={t("borderWidth")}>
417→            {([
418→              { key: "thin" as const, value: 1 },
419→              { key: "normal" as const, value: 2 },
420→              { key: "thick" as const, value: 4 },
421→            ]).map((w) => (
422→              <div
423→                key={w.value}
424→                className="ctx-item flex items-center gap-2"
425→                onClick={() => {
426→                  nodeIds.forEach((id) => updateNodeBorder(id, w.value, undefined));
427→                  onClose();
428→                }}
429→              >
430→                <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor">
431→                  <rect x="2" y={7 - w.value / 2} width="16" height={w.value} fill="currentColor" />
432→                </svg>
433→                {t(w.key)}
434→              </div>
435→            ))}
436→          </SubMenu>
437→          <SubMenu label={t("borderLineStyle")}>
438→            {([
439→              { key: "solid" as const, value: "solid" as const },
440→              { key: "dashed" as const, value: "dashed" as const },
441→              { key: "dotted" as const, value: "dotted" as const },
442→            ]).map((s) => (
443→              <div
444→                key={s.value}
445→                className="ctx-item flex items-center gap-2"
446→                onClick={() => {
447→                  nodeIds.forEach((id) => updateNodeBorder(id, undefined, s.value));
448→                  onClose();
449→                }}
450→              >
451→                <svg width="20" height="14" viewBox="0 0 20 14" fill="none" stroke="currentColor" strokeWidth="2">
452→                  <line
453→                    x1="2" y1="7" x2="18" y2="7"
454→                    strokeDasharray={s.value === "dashed" ? "4 2" : s.value === "dotted" ? "1.5 1.5" : undefined}
455→                  />
456→                </svg>
457→                {t(s.key)}
458→              </div>
459→            ))}
