461→          <SubMenu label={t("order")}>
462→            <div className="ctx-item flex items-center gap-2" onClick={() => { reorderNodes(nodeIds, "front"); onClose(); }}>
463→              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
