 40→// Module-level state for reconnection: fixed endpoint position
 41→let reconnectFixedEnd: { x: number; y: number; position: import("@xyflow/react").Position } | null = null;
 42→
 43→function inferTargetPosition(sourceX: number, sourceY: number, targetX: number, targetY: number): Position {
 44→  const dx = targetX - sourceX;
 45→  const dy = targetY - sourceY;
 46→  if (Math.abs(dx) > Math.abs(dy)) {
 47→    return dx > 0 ? Position.Left : Position.Right;
 48→  }
 49→  return dy > 0 ? Position.Top : Position.Bottom;
 50→}
 51→
 52→function ReconnectConnectionLine({ fromX, fromY, toX, toY, fromPosition, toPosition }: ConnectionLineComponentProps<FlowNode>) {
 53→  let startX: number, startY: number, endX: number, endY: number;
 54→  let startPos = fromPosition;
 55→  let endPos = toPosition;
 56→
 57→  if (reconnectFixedEnd) {
 58→    // During reconnection: draw from fixed end to cursor
 59→    startX = reconnectFixedEnd.x;
 60→    startY = reconnectFixedEnd.y;
 61→    startPos = reconnectFixedEnd.position;
 62→    endX = toX;
 63→    endY = toY;
 64→    // Infer target position from direction so bezier doesn't overshoot cursor
 65→    endPos = inferTargetPosition(startX, startY, endX, endY);
 66→  } else {
 67→    // Normal connection: draw from drag origin to cursor
 68→    startX = fromX;
 69→    startY = fromY;
 70→    endX = toX;
 71→    endY = toY;
 72→    endPos = inferTargetPosition(startX, startY, endX, endY);
 73→  }
 74→
 75→  const [path] = getBezierPath({
 76→    sourceX: startX,
 77→    sourceY: startY,
 78→    sourcePosition: startPos,
 79→    targetX: endX,
 80→    targetY: endY,
 81→    targetPosition: endPos,
 82→  });
 83→
 84→  return (
 85→    <g>
 86→      <path d={path} fill="none" stroke="var(--primary)" strokeWidth={2} strokeDasharray="6 3" />
 87→    </g>
 88→  );
 89→}
