 91→export function FlowCanvas() {
 92→  perfCount("FlowCanvas");
 93→  const nodes = useFlowStore((s) => s.nodes);
 94→  const edges = useFlowStore((s) => s.edges);
 95→  const onNodesChange = useFlowStore((s) => s.onNodesChange);
 96→  const onEdgesChange = useFlowStore((s) => s.onEdgesChange);
 97→  const addEdge = useFlowStore((s) => s.addEdge);
 98→  const addNode = useFlowStore((s) => s.addNode);
 99→  const reconnectEdge = useFlowStore((s) => s.reconnectEdge);
100→
101→  const placeComponentInstance = useFlowStore((s) => s.placeComponentInstance);
102→  const [dragPayload] = useDnDContext();
103→  const reactFlowInstance = useRef<ReactFlowInstance<FlowNode, FlowEdge> | null>(null);
104→  const { menu, open: openMenu, close: closeMenu } = useContextMenu();
105→  // Track if a node/edge-specific handler already opened the context menu
106→  const menuHandledRef = useRef(false);
107→  const { guides, onNodeDrag, applySnap, clearGuides } = useSnapGuides(nodes);
108→
109→  // Predictive input: compute all valid ghost nodes for all directions
110→  const addNodeWithData = useFlowStore((s) => s.addNodeWithData);
111→  const DIRECTIONS: PredictiveDirection[] = useMemo(() => ["top", "right", "bottom", "left"], []);
112→  const OVERLAP_MARGIN = 10;
113→
114→  // Global candidate index for Tab cycling (applies to all visible ghosts)
115→  const [ghostCandidateIndex, setGhostCandidateIndex] = useState(0);
116→
117→  // Cache candidates per source node (for Tab cycling)
118→  const candidatesMap = useMemo(() => {
119→    const map: Record<string, ReturnType<typeof computeCandidates>> = {};
120→    for (const node of nodes) {
121→      if (node.id.startsWith(GHOST_NODE_ID)) continue;
122→      if (node.data.componentParentId) continue;
123→      map[node.id] = computeCandidates(node, edges, nodes);
124→    }
125→    return map;
126→  }, [nodes, edges]);
127→
128→  const allGhosts = useMemo(() => {
129→    const ghostNodes: FlowNode[] = [];
130→    const ghostEdges: FlowEdge[] = [];
131→
132→    // Show ghosts only for the first selected node
133→    const selectedNode = nodes.find((n) => n.selected && !n.id.startsWith(GHOST_NODE_ID) && !n.data.componentParentId);
134→    if (selectedNode) {
135→      const node = selectedNode;
136→      const candidates = candidatesMap[node.id];
137→      if (!candidates || candidates.length === 0) return { ghostNodes, ghostEdges };
138→
139→      for (const dir of DIRECTIONS) {
140→        // Pick candidate: use global cycled index for all ghosts
141→        const ghostKey = `${node.id}_${dir}`;
142→        const candIdx = ((ghostCandidateIndex % candidates.length) + candidates.length) % candidates.length;
143→        const candidate = candidates[candIdx];
144→
145→        // Skip if edge already connected in this direction
146→        const hasEdge = edges.some((e) => {
147→          if (e.data?.isBridgeEdge) return false;
148→          return (e.source === node.id && e.sourceHandle === `${dir}-source`) ||
149→                 (e.target === node.id && e.targetHandle === `${dir}-target`);
150→        });
151→        if (hasEdge) continue;
152→
153→        // Compute ghost position
154→        const ghostPos = computeGhostPosition(node, dir, candidate.nodeData.shape);
155→
156→        // Skip if overlapping existing node
157→        const hasOverlap = nodes.some((other) => {
158→          if (other.id === node.id || other.id.startsWith(GHOST_NODE_ID)) return false;
159→          if (other.data.componentParentId) return false;
160→          const ow = other.measured?.width ?? (other.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
161→          const oh = other.measured?.height ?? (other.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
162→          return ghostPos.x < other.position.x + ow - OVERLAP_MARGIN &&
163→                 ghostPos.x + ghostPos.gw > other.position.x + OVERLAP_MARGIN &&
164→                 ghostPos.y < other.position.y + oh - OVERLAP_MARGIN &&
165→                 ghostPos.y + ghostPos.gh > other.position.y + OVERLAP_MARGIN;
166→        });
167→        if (hasOverlap) continue;
168→
169→        const ghostId = `${GHOST_NODE_ID}${ghostKey}`;
170→        const handles = DIRECTION_HANDLES[dir];
171→        const ghostSize = getDefaultSize(candidate.nodeData.shape);
172→
173→        ghostNodes.push({
174→          id: ghostId,
175→          type: candidate.nodeData.shape,
176→          position: { x: ghostPos.x, y: ghostPos.y },
177→          data: {
178→            ...candidate.nodeData,
179→            label: "...",
180→            ghostTargetHandle: handles.targetHandle,
181→            ghostSourceNodeId: node.id,
182→            ghostDirection: dir,
183→            ghostCandidateIndex: candIdx,
184→          },
185→          style: { width: ghostSize.width, height: ghostSize.height },
186→          selectable: false,
187→          draggable: false,
188→        });
189→
190→        ghostEdges.push({
191→          id: `__ghost_edge__${ghostKey}`,
192→          source: node.id,
193→          target: ghostId,
194→          sourceHandle: handles.sourceHandle,
195→          targetHandle: handles.targetHandle,
196→          type: "labeled",
197→          style: { strokeDasharray: "6 3" },
198→          selectable: false,
199→          markerEnd: { type: MarkerType.ArrowClosed },
200→          data: {
201→            edgeType: candidate.edgeData?.edgeType ?? "bezier",
202→            markerEnd: candidate.edgeData?.markerEnd ?? "arrowclosed",
203→            markerStart: candidate.edgeData?.markerStart,
204→            strokeStyle: "dashed",
205→          },
206→        } as FlowEdge);
207→      }
208→    }
209→
210→    return { ghostNodes, ghostEdges };
211→  }, [nodes, edges, DIRECTIONS, OVERLAP_MARGIN, candidatesMap, ghostCandidateIndex]);
212→
213→  const hasGhosts = allGhosts.ghostNodes.length > 0;
214→
215→  // Inject ghost nodes/edges into arrays for rendering
216→  const nodesWithGhost = useMemo(
217→    () => allGhosts.ghostNodes.length > 0 ? [...nodes, ...allGhosts.ghostNodes] : nodes,
218→    [nodes, allGhosts.ghostNodes],
219→  );
220→  const edgesWithGhost = useMemo(
221→    () => allGhosts.ghostEdges.length > 0 ? [...edges, ...allGhosts.ghostEdges] : edges,
222→    [edges, allGhosts.ghostEdges],
223→  );
224→
225→  // Minimap toggle (persisted in localStorage, default: hidden)
226→  const [showMinimap, setShowMinimap] = useState(() => {
227→    if (typeof window === "undefined") return false;
228→    return localStorage.getItem(MINIMAP_STORAGE_KEY) === "true";
229→  });
230→  const toggleMinimap = useCallback(() => {
231→    setShowMinimap((prev) => {
232→      const next = !prev;
233→      localStorage.setItem(MINIMAP_STORAGE_KEY, String(next));
234→      return next;
235→    });
236→  }, []);
237→
238→  // Help panel toggle
239→  const [showHelp, setShowHelp] = useState(false);
240→  const toggleHelp = useCallback(() => setShowHelp((p) => !p), []);
241→  const { t } = useLocale();
242→
243→  // Track edge reconnection initiated from ring handles
244→  const reconnectingEdgeRef = useRef<FlowEdge | null>(null);
245→  const reconnectingTypeRef = useRef<"source" | "target" | null>(null);
246→
247→  const setEdgeVisibility = useCallback((edgeId: string | null, hidden: boolean) => {
248→    if (!edgeId) return;
249→    const edgeEl = document.querySelector(`.react-flow__edge[data-id="${CSS.escape(edgeId)}"]`);
250→    if (hidden) {
251→      edgeEl?.classList.add("reconnecting");
252→    } else {
253→      edgeEl?.classList.remove("reconnecting");
254→    }
255→  }, []);
256→
257→  const onConnectStart = useCallback(
258→    (_event: MouseEvent | TouchEvent, params: { nodeId: string | null; handleId: string | null; handleType: "source" | "target" | null }) => {
259→      if (!params.nodeId || !params.handleId || !params.handleType) return;
260→      const currentEdges = useFlowStore.getState().edges;
261→      // Reconnect priority:
262→      // 1. Selected edge at this position (same pos, either source or target handle) → always reconnect
263→      //    Handles at the same position overlap visually, so user may grab the "wrong" one
264→      // 2. Exactly one edge on the dragged handle → reconnect it
265→      // 3. Multiple edges on handle + one selected → reconnect the selected one
266→      // 4. Otherwise → new connection mode
267→      const handlePos = params.handleId.split("-")[0]; // e.g. "bottom" from "bottom-source"
268→      const sourceHandleId = `${handlePos}-source`;
269→      const targetHandleId = `${handlePos}-target`;
270→
271→      // Priority 1: selected edge at this position (check both source and target handles)
272→      const selectedAtPos = currentEdges.find((e) => {
273→        if (!e.selected || e.data?.isBridgeEdge) return false;
274→        return (e.source === params.nodeId && e.sourceHandle === sourceHandleId) ||
275→               (e.target === params.nodeId && e.targetHandle === targetHandleId);
276→      });
277→
278→      let connectedEdge: FlowEdge | undefined;
279→      let actualReconnectType: "source" | "target" | null = null;
280→
281→      if (selectedAtPos) {
282→        connectedEdge = selectedAtPos;
283→        // Determine which side of the edge connects to this node at this position
284→        actualReconnectType = (selectedAtPos.source === params.nodeId && selectedAtPos.sourceHandle === sourceHandleId)
285→          ? "source" : "target";
286→      } else {
287→        // Priority 2-3: fall back to edges on the exact dragged handle
288→        const edgesOnHandle = currentEdges.filter((e) => {
289→          if (e.data?.isBridgeEdge) return false;
290→          if (params.handleType === "source") return e.source === params.nodeId && e.sourceHandle === params.handleId;
291→          return e.target === params.nodeId && e.targetHandle === params.handleId;
292→        });
293→        connectedEdge = edgesOnHandle.length === 1
294→          ? edgesOnHandle[0]
295→          : edgesOnHandle.find((e) => e.selected);
296→        actualReconnectType = connectedEdge ? params.handleType : null;
297→      }
298→
299→      reconnectingEdgeRef.current = connectedEdge ?? null;
300→      reconnectingTypeRef.current = actualReconnectType;
301→      reconnectFixedEnd = null;
302→      if (connectedEdge && actualReconnectType) {
303→        setEdgeVisibility(connectedEdge.id, true);
304→        // Calculate the FIXED endpoint (the end NOT being dragged) for connection line rendering
305→        const fixedType = actualReconnectType === "source" ? "target" : "source";
306→        const fixedNodeId = fixedType === "source" ? connectedEdge.source : connectedEdge.target;
307→        const fixedHandleId = fixedType === "source" ? connectedEdge.sourceHandle : connectedEdge.targetHandle;
308→        if (fixedNodeId && fixedHandleId && reactFlowInstance.current) {
309→          const handleEl = document.querySelector(
310→            `.react-flow__node[data-id="${CSS.escape(fixedNodeId)}"] .react-flow__handle[data-handleid="${CSS.escape(fixedHandleId)}"]`
311→          );
312→          if (handleEl) {
313→            const rect = handleEl.getBoundingClientRect();
314→            const pos = reactFlowInstance.current.screenToFlowPosition({
315→              x: rect.x + rect.width / 2,
316→              y: rect.y + rect.height / 2,
317→            });
318→            // Determine the Position enum from handle ID (e.g. "top-source" → Position.Top)
319→            const posStr = fixedHandleId.split("-")[0] as "top" | "right" | "bottom" | "left";
320→            const posMap: Record<string, import("@xyflow/react").Position> = {
321→              top: Position.Top, right: Position.Right, bottom: Position.Bottom, left: Position.Left,
322→            };
323→            reconnectFixedEnd = { x: pos.x, y: pos.y, position: posMap[posStr] ?? Position.Top };
324→          }
325→        }
326→      }
327→    },
328→    [setEdgeVisibility]
329→  );
330→
331→  const onConnect = useCallback(
332→    (connection: Connection) => {
333→      if (!connection.source || !connection.target) return;
334→      const oldEdge = reconnectingEdgeRef.current;
335→      const reconnectType = reconnectingTypeRef.current;
336→      if (oldEdge && reconnectType) {
337→        // Determine which node in the connection is the new drop target
338→        const origNodeId = reconnectType === "source" ? oldEdge.source : oldEdge.target;
339→        const oldHandleId = reconnectType === "source" ? oldEdge.sourceHandle : oldEdge.targetHandle;
340→
341→        let newNodeId: string;
342→        let newHandle: string | null;
343→
344→        if (connection.source === connection.target) {
345→          // Same node: pick the handle that differs from the original
346→          newNodeId = connection.source!;
347→          const candidate = [connection.sourceHandle, connection.targetHandle].find(h => h && h !== oldHandleId);
348→          newHandle = candidate ?? null;
349→        } else {
350→          newNodeId = connection.source === origNodeId ? connection.target! : connection.source!;
351→          newHandle = connection.source === origNodeId ? connection.targetHandle : connection.sourceHandle;
352→        }
353→
354→        // Normalize handle ID suffix: React Flow may swap source/target in the connection object,
355→        // so the handle ID might have the wrong type suffix (e.g. "top-source" when we need "top-target")
356→        if (newHandle) {
357→          const pos = newHandle.split("-")[0];
358→          newHandle = `${pos}-${reconnectType}`;
359→        }
360→
361→        // Guard: if no valid handle found, abort reconnection
362→        if (!newHandle) return;
363→
364→        const newConnection: Connection = reconnectType === "source"
365→          ? { source: newNodeId, sourceHandle: newHandle, target: oldEdge.target, targetHandle: oldEdge.targetHandle ?? null }
366→          : { source: oldEdge.source, sourceHandle: oldEdge.sourceHandle ?? null, target: newNodeId, targetHandle: newHandle };
367→
368→        reconnectEdge(oldEdge, newConnection);
369→        setEdgeVisibility(oldEdge.id, false);
370→        reconnectingEdgeRef.current = null;
371→        reconnectingTypeRef.current = null;
372→        reconnectFixedEnd = null;
373→      } else {
374→        // Normalize handle IDs: React Flow may swap source/target when dragging from a target handle,
375→        // causing sourceHandle to have "-target" suffix and vice versa
376→        let srcHandle = connection.sourceHandle;
377→        let tgtHandle = connection.targetHandle;
378→        if (srcHandle) {
379→          const pos = srcHandle.split("-")[0];
380→          srcHandle = `${pos}-source`;
381→        }
382→        if (tgtHandle) {
383→          const pos = tgtHandle.split("-")[0];
384→          tgtHandle = `${pos}-target`;
385→        }
386→        addEdge(
387→          connection.source,
388→          connection.target,
389→          undefined,
390→          srcHandle,
391→          tgtHandle,
392→        );
393→      }
394→    },
395→    [addEdge, reconnectEdge, setEdgeVisibility]
396→  );
