// Fallback context menu: panOnDrag=[1,2] blocks onPaneContextMenu for right-click.
// This native handler on the wrapper catches the bubbled event and opens the menu
// for selected elements when no node/edge handler has already handled it.
const openMenuRef = useRef(openMenu);
openMenuRef.current = openMenu;
useEffect(() => {
  const el = wrapperRef.current;
  if (!el) return;
  const handler = (e: MouseEvent) => {
    if (menuHandledRef.current) {
      menuHandledRef.current = false;
      return;
    }
    const state = useFlowStore.getState();
    const selectedNodeIds = state.nodes.filter((n) => n.selected).map((n) => n.id);
    const selectedEdgeIds = state.edges.filter((e) => e.selected).map((e) => e.id);
    if (selectedNodeIds.length > 0 || selectedEdgeIds.length > 0) {
      e.preventDefault();
      openMenuRef.current(e as unknown as React.MouseEvent, selectedNodeIds, selectedEdgeIds);
    }
  };
  el.addEventListener("contextmenu", handler);
  return () => el.removeEventListener("contextmenu", handler);
}, []);

