// Fallback context menu for right-click on pane with selected elements.
// panOnDrag=[1,2] blocks React Flow's onPaneContextMenu for right-click (button 2).
// This React handler on the wrapper div catches the bubbled synthetic event
// after node/edge/pane handlers, and opens the menu for selected elements.
const handleWrapperContextMenu = useCallback(
  (e: React.MouseEvent) => {
    // Skip if a node/edge handler already opened the menu
    if (menuHandledRef.current) {
      menuHandledRef.current = false;
      return;
    }
    const state = useFlowStore.getState();
    const sNodes = state.nodes.filter((n) => n.selected).map((n) => n.id);
    const sEdges = state.edges.filter((ed) => ed.selected).map((ed) => ed.id);
    if (sNodes.length > 0 || sEdges.length > 0) {
      e.preventDefault();
      openMenu(e, sNodes, sEdges);
    }
  },
  [openMenu]
);

